// Turn the group's user members into one upsert + deactivate SQL for the watchlist.
// Members in the group -> active=true; anyone in the watchlist no longer in the group -> active=false.
const resp = $input.first().json;
const items = (resp.value || []).filter(u => u && u.id);
if (!items.length) {
  // Safety: never deactivate everyone if the call returned nothing.
  return [{ json: { sql: "SELECT 'no members returned - watchlist left unchanged' AS note;", count: 0 } }];
}
const esc = s => String(s == null ? '' : s).replace(/'/g, "''");
const vals = items.map(u => "('" + esc(u.id) + "','" + esc(u.displayName || u.userPrincipalName || '') + "')").join(',');
const ids = items.map(u => "'" + esc(u.id) + "'").join(',');
const sql =
  "INSERT INTO watchlist (graph_user_id, display_name, active) " +
  "SELECT v.graph_user_id, v.display_name, true FROM (VALUES " + vals + ") AS v(graph_user_id, display_name) " +
  "ON CONFLICT (graph_user_id) DO UPDATE SET display_name = EXCLUDED.display_name, active = true; " +
  "UPDATE watchlist SET active = false WHERE graph_user_id NOT IN (" + ids + ");";
return [{ json: { sql, count: items.length } }];
